import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Ante (Antigma Labs) — Self-Organizing Terminal Coding Agent","description":"","frontmatter":{"title":"Ante (Antigma Labs) — Self-Organizing Terminal Coding Agent","status":"complete"},"headers":[],"relativePath":"research/agents/ante/index.md","filePath":"research/agents/ante/index.md"}'),r={name:"research/agents/ante/index.md"};function i(o,e,l,c,d,p){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="ante" tabindex="-1">Ante <a class="header-anchor" href="#ante" aria-label="Permalink to &quot;Ante&quot;">​</a></h1><blockquote><p>Rust-built, self-contained terminal coding agent by Antigma Labs — designed around self-organizing multi-agent intelligence with lock-free scheduling and full offline capability.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><strong>Ante</strong> is an in-terminal coding agent built from scratch in Rust by <strong>Antigma Labs</strong>. Unlike most AI coding tools that layer on top of existing agent frameworks or scripting runtimes, Ante is a ground-up, first-principles implementation — its own runtime, its own scheduler, its own orchestration layer. The result is a fast, self-contained binary with no external framework dependencies.</p><p>Antigma Labs&#39; mission is <em>&quot;building substrate for self-organizing intelligence.&quot;</em> The company name is a play on &quot;anti-Enigma,&quot; inspired by Alan Turing&#39;s codebreaking work at Bletchley Park. Their core philosophy treats agents as teammates and the user as just another agent in the system — not a privileged operator issuing commands, but a peer collaborator. This worldview extends to broader beliefs around individual AI sovereignty: Antigma frames personal AI tooling as a fundamental right, analogous to &quot;the right to bear arms&quot; in the AI era.</p><p>Ante sits in a distinctive corner of the AI coding agent landscape. Where tools like Claude Code and Codex prioritize cloud-connected, single-model agentic loops, Ante emphasizes <strong>offline-first operation</strong>, <strong>multi-agent orchestration</strong>, and <strong>Rust-level performance guarantees</strong>. It can run entirely self-contained with local models — no cloud dependency required — or connect to cloud LLM providers when available. A meta-agent layer orchestrates multiple sub-agents, allowing complex tasks to be decomposed and parallelized across a lock-free scheduling runtime.</p><h3 id="what-makes-ante-special" tabindex="-1">What Makes Ante Special <a class="header-anchor" href="#what-makes-ante-special" aria-label="Permalink to &quot;What Makes Ante Special&quot;">​</a></h3><ol><li><p><strong>Rust From Scratch</strong>: Not a wrapper around Python or Node.js agent frameworks. Ante is written entirely in Rust, giving it memory safety, zero-cost abstractions, and a lock-free concurrency model purpose-built for multi-agent orchestration.</p></li><li><p><strong>Self-Organizing Multi-Agent Architecture</strong>: A meta-agent orchestrates dynamically spawned sub-agents. Tasks are decomposed and distributed, with the user treated as a peer agent rather than a privileged controller.</p></li><li><p><strong>Offline-First Design</strong>: Ante is fully self-contained and can operate without any cloud dependency. Paired with Antigma&#39;s own inference stack (see <code>nanochat-rs</code>), it can run local models entirely on-device.</p></li><li><p><strong>Lock-Free Scheduling</strong>: The Rust runtime uses lock-free data structures for agent scheduling and orchestration, avoiding the mutex contention that plagues thread-based agent systems.</p></li><li><p><strong>Own Inference Stack</strong>: Antigma Labs builds their own components — their <code>nanochat-rs</code> project is a tiny GPT-style cognitive core in pure Rust built on HuggingFace Candle, and <code>mcp-sdk</code> is a minimalistic Rust MCP implementation. They don&#39;t just consume the ecosystem; they build it.</p></li><li><p><strong>Benchmark Integrity Advocacy</strong>: Ante was notably used as the investigative tool to write a forensic analysis exposing benchmark manipulation on Terminal-Bench 2.0 — a 13-minute deep-dive blog post titled <em>&quot;How to Achieve #1 on Terminal Bench (and Why We Can&#39;t Have Nice Things).&quot;</em></p></li></ol><h2 id="benchmark-scores" tabindex="-1">Benchmark Scores <a class="header-anchor" href="#benchmark-scores" aria-label="Permalink to &quot;Benchmark Scores&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Configuration</th><th>Rank</th><th>Score</th></tr></thead><tbody><tr><td>Terminal-Bench 2.0</td><td>Ante + Gemini 3 Pro</td><td>#17</td><td>69.4%</td></tr><tr><td>Terminal-Bench 1.0</td><td>Ante + Claude Sonnet 4.5</td><td>#4</td><td>60.3%</td></tr></tbody></table><h2 id="key-stats" tabindex="-1">Key Stats <a class="header-anchor" href="#key-stats" aria-label="Permalink to &quot;Key Stats&quot;">​</a></h2><ul><li><strong>Language</strong>: Rust (built from scratch, no agent framework dependency)</li><li><strong>License</strong>: Proprietary (core); open-source components on GitHub</li><li><strong>Offline mode</strong>: Full local operation with no cloud dependency</li><li><strong>Open-source projects</strong>: <a href="https://github.com/AntigmaLabs/mcp-sdk" target="_blank" rel="noreferrer"><code>mcp-sdk</code></a> (64 ★), <a href="https://github.com/AntigmaLabs/nanochat-rs" target="_blank" rel="noreferrer"><code>nanochat-rs</code></a> (62 ★)</li><li><strong>Three pillars</strong>: Privacy (private networks), Trust (trust boundaries), Tribute (compute united)</li><li><strong>Docs</strong>: <a href="https://docs.antigma.ai" target="_blank" rel="noreferrer">docs.antigma.ai</a> (access-restricted)</li></ul><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a Glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a Glance&quot;">​</a></h2><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│            User (Terminal)              │</span></span>
<span class="line"><span>└────────────────┬────────────────────────┘</span></span>
<span class="line"><span>                 │</span></span>
<span class="line"><span>       ┌─────────▼──────────┐</span></span>
<span class="line"><span>       │    Meta Agent       │</span></span>
<span class="line"><span>       │  (Orchestrator)     │</span></span>
<span class="line"><span>       └──┬──────┬───────┬──┘</span></span>
<span class="line"><span>          │      │       │</span></span>
<span class="line"><span>    ┌─────▼┐  ┌──▼───┐ ┌─▼────────┐</span></span>
<span class="line"><span>    │Sub   │  │Sub   │ │Sub       │</span></span>
<span class="line"><span>    │Agent │  │Agent │ │Agent     │</span></span>
<span class="line"><span>    │(task)│  │(task)│ │(task)    │</span></span>
<span class="line"><span>    └──┬───┘  └──┬───┘ └──┬──────┘</span></span>
<span class="line"><span>       │         │        │</span></span>
<span class="line"><span>    ┌──▼─────────▼────────▼──────┐</span></span>
<span class="line"><span>    │  Rust Runtime               │</span></span>
<span class="line"><span>    │  Lock-free Scheduler        │</span></span>
<span class="line"><span>    │  Offline / Cloud LLM Layer  │</span></span>
<span class="line"><span>    └─────────────────────────────┘</span></span></code></pre></div><h2 id="files-in-this-research" tabindex="-1">Files in This Research <a class="header-anchor" href="#files-in-this-research" aria-label="Permalink to &quot;Files in This Research&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Contents</th></tr></thead><tbody><tr><td><a href="./architecture.html">architecture.md</a></td><td>Rust runtime design, lock-free scheduler, meta-agent orchestration layer</td></tr><tr><td><a href="./agentic-loop.html">agentic-loop.md</a></td><td>Meta-agent → sub-agent task decomposition and execution loop</td></tr><tr><td><a href="./tool-system.html">tool-system.md</a></td><td>MCP integration via <code>mcp-sdk</code>, tool invocation from sub-agents</td></tr><tr><td><a href="./context-management.html">context-management.md</a></td><td>Context sharing between agents, offline vs. cloud model context strategies</td></tr><tr><td><a href="./unique-patterns.html">unique-patterns.md</a></td><td>Lock-free scheduling, self-organizing intelligence, own inference stack</td></tr><tr><td><a href="./benchmarks.html">benchmarks.md</a></td><td>Terminal-Bench 1.0 and 2.0 results, benchmark integrity analysis</td></tr><tr><td><a href="./references.html">references.md</a></td><td>Links to Antigma Labs site, GitHub repos, blog posts, docs</td></tr></tbody></table>`,16)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
